// Load deferred_fires from static data, expire anything older than 7 days,
// and emit one item per entry for processing.
const staticData = $getWorkflowStaticData('global');
staticData.deferred_fires = staticData.deferred_fires || [];

const now = Date.now();
const sevenDays = 7 * 24 * 60 * 60 * 1000;

const expired = [];
const live = [];
for (const entry of staticData.deferred_fires) {
  if (now - (entry.deferredAt || 0) > sevenDays) expired.push(entry);
  else live.push(entry);
}
staticData.deferred_fires = live;

if (live.length === 0 && expired.length === 0) {
  return [{ json: { empty: true, expired: [], live: [] } }];
}

return [{
  json: {
    empty: live.length === 0,
    expired,
    live,
    total: live.length,
  }
}];

