// Emit one item per live deferred fire, FIFO (oldest first).
const input = $input.first().json;
const live = (input.live || []).slice().sort((a, b) => (a.deferredAt || 0) - (b.deferredAt || 0));
return live.map(entry => ({ json: entry }));

// Classify the response: 200 → drained, 429 → still at cap, other → failed.
const entry = $('Emit per entry (FIFO)').item.json;
const resp = $input.first().json;
const status = resp.statusCode || resp.status || 0;
const staticData = $getWorkflowStaticData('global');
staticData.deferred_fires = staticData.deferred_fires || [];

if (status === 200 || status === 201) {
  // Remove from list
  staticData.deferred_fires = staticData.deferred_fires.filter(e =>
    !(e.issueId === entry.issueId && e.deferredAt === entry.deferredAt)
  );
  return [{ json: { ...entry, outcome: 'drained', response: resp.body } }];
}
if (status === 429) {
  // Stay deferred — stop processing further entries this cycle
  return [{ json: { ...entry, outcome: 'still-capped', response: resp.body } }];
}
// Other error: remove from list, alert. Dropping protects the list from unfixable entries.
staticData.deferred_fires = staticData.deferred_fires.filter(e =>
  !(e.issueId === entry.issueId && e.deferredAt === entry.deferredAt)
);
return [{ json: { ...entry, outcome: 'failed', statusCode: status, response: resp.body } }];

